import{_ as e,c as l,o as a,aK as n}from"./chunks/framework.CAO7UY6-.js";const g=JSON.parse('{"title":"英语随记","description":"","frontmatter":{},"headers":[{"level":3,"title":"单词辨析","slug":"单词辨析","link":"#单词辨析","children":[]},{"level":3,"title":"固定搭配","slug":"固定搭配","link":"#固定搭配","children":[]},{"level":3,"title":"比较级","slug":"比较级","link":"#比较级","children":[]},{"level":3,"title":"现在/过去分词","slug":"现在-过去分词","link":"#现在-过去分词","children":[]},{"level":3,"title":"可数/不可数名词","slug":"可数-不可数名词","link":"#可数-不可数名词","children":[]},{"level":3,"title":"前后缀","slug":"前后缀","link":"#前后缀","children":[]}],"relativePath":"gaozhong/英语/总结文章/英语随记.md","filePath":"gaozhong/英语/总结文章/英语随记.md","lastUpdated":1738597217000}'),s={name:"gaozhong/英语/总结文章/英语随记.md"};function t(o,i,r,p,h,c){return a(),l("div",null,i[0]||(i[0]=[n(`<h1 id="英语随记" tabindex="-1">英语随记 <a class="header-anchor" href="#英语随记" aria-label="Permalink to &quot;英语随记&quot;">​</a></h1><p>英语做单选题，很有用。能考</p><ol><li>单词</li><li>语法</li><li>短语</li><li>句型</li><li>交际……</li></ol><h3 id="单词辨析" tabindex="-1">单词辨析 <a class="header-anchor" href="#单词辨析" aria-label="Permalink to &quot;单词辨析&quot;">​</a></h3><ul><li>形容词“effective”和“efficient”的区别</li></ul><p>单词“effective”和“efficient”之间有哪些区别？这两个词语都是形容词，而且它们都和名词“effect 效果，影响”同源，用来描述一件事或行动所产生的正面、积极的效果。</p><p>首先，“effective”的意思是“有效果的”，指“得到了预期的结果”；但“efficient”强调不光有效果，而且效率还很高。</p><p>总结：首先，“efficient 高效的”事物一定是“effective 有效的”，而“effective 有效的”事物却不一定都是“efficient 高效的”；其次，“effective”只能用来形容“事物有效”，比如“药物有疗效。A drug is effective.”，通常不能用来形容人，但“efficient”则既可以指“系统、机器等效率高”，也可以指人“办事有效率、能干”。最后，“effective”还可以指“法律法规生效的”，“efficient”则没有这层含义。</p><h3 id="固定搭配" tabindex="-1">固定搭配 <a class="header-anchor" href="#固定搭配" aria-label="Permalink to &quot;固定搭配&quot;">​</a></h3><ul><li>remember to do 与 remember doing 有什么区别呢？</li></ul><div class="language-md vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">md</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &quot;Remember to do&quot; 用于提醒自己或他人去做某事。</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &quot;Remember doing&quot; 用于回忆起过去已经发生的事情。</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">例句：</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Please remember to buy milk on your way home. (请记得在回家的路上买牛奶。)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> I remember seeing him at the party last night. (我记得昨晚在派对上见过他。)</span></span></code></pre></div><ul><li>be willing to do</li></ul><p>愿意去做某事</p><ul><li>be unwilling to do</li></ul><p>不愿意去做某事</p><ul><li>try to do sth. 尽力做某事（很困难，大概率会失败）</li></ul><p>例如初中学的尽某人最大的努力做某事：</p><p>try one&#39;s best to do sth.</p><ul><li><p>try doing sth. 尝试做某事</p></li><li><p>I don&#39;t feel very well 和 I am not feeling very well 有什么区别？如果难以说明的话，请教我一下例句。</p></li></ul><p>它们是一样的意思。</p><ul><li>have a talent for</li></ul><p>对……有天赋</p><ul><li><p>be forced to 被迫去做某事</p></li><li><p>be concerned with 和 be concerned about 有什么区别？</p></li></ul><p>concern about 和 concern with 当表达“关心，关注”等含义的时候，用法可以互换，没有多大区别。但是，concern with 除上述含义以外，还有“与...相关，与....联系”的含义，但是 concern about 就没有此层含义。</p><ul><li>be helpful in/for sb/to do</li></ul><div class="language-md vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">md</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">1.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> be helpful in doing sth.</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">We hope this leaflet has been helpful in answering your questions.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">我们希望这个宣传单可以帮助您找到您想要的答案</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">2.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> it is helpful (for sb) to do sth</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">It is helpful to discuss your problems with your friends.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">跟你的朋友们聊聊你遇到的问题是有好处的。这里的 It 是形式主语，真正的主语是 to 后面的句子</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">3.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> be helpful for sb 对某人事有益的</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Music with the sounds of the ocean or bird song can be helpful for some.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">大海的声音或者鸟叫声对你的睡眠时很有帮助的</span></span></code></pre></div><ul><li>invite sb to do (to sth) 邀请某人去做某事</li></ul><p>例句：[动词 + 名词短语] Have you been invited to their party? 你被邀请参加他们的聚会了吗？</p><h3 id="比较级" tabindex="-1">比较级 <a class="header-anchor" href="#比较级" aria-label="Permalink to &quot;比较级&quot;">​</a></h3><ul><li><p>much/more/most</p></li><li><p>many/more/most</p></li><li><p>good/better/best</p></li><li><p>bad/worse/worst</p></li><li><p>big/bigger/biggest</p><p>（复数 bigs 第三人称单数 bigs 现在分词 bigging 过去式 bigged 或 bug 过去分词 bigged 或 bug 比较级 bigger 最高级 biggest）</p></li></ul><h3 id="现在-过去分词" tabindex="-1">现在/过去分词 <a class="header-anchor" href="#现在-过去分词" aria-label="Permalink to &quot;现在/过去分词&quot;">​</a></h3><ol><li>做 doing</li><li>被做 done</li><li>要做去做还未做 to do</li><li>现在分词的构成方法 <ol><li>(1) 一般情况下，在动词后加-ing 构成:work-working,sleep-sleeping 等</li><li>(2) 以不发音的-e 结尾的动词，去掉 e 后再加-ing:smile-smiling,move-moving 等</li><li>(3) 以重读闭音节或 r 音节结尾且末尾只有一个辅音字母动词，要双写末尾的辅音字母再加-ing: sit-sitting, plan-planning,refer-referring, get-getting 等</li><li>(4) 以字母 ie 结尾的动词，通常将 ie 改为 y，再加 ing: die-dying, lie-lying 等。</li><li>(5) 不规则变化：如 picnic(野餐) 的现在分词为 picnicking 等需要特殊记忆。</li></ol></li></ol><p>常见的是否需要双写的现在分词。</p><p><strong>需要双写的现在分词：</strong></p><ul><li>sit，sat，sat，sitting</li><li>plan，planned，planned，planning</li><li>refer，referred，referred，referring</li><li>get，got，got，getting</li><li>run，ran，run，running</li><li>admit，admitted，admitted，admitting（承认；接纳，接收（入学）；承认……有效；v.）</li><li>clap，clapped，clapped，clapping（鼓掌）</li></ul><p><strong>其实不需要双写的现在分词：</strong></p><ul><li>sleep，slept，slept，sleeping</li><li>fall，fell，fallen，falling</li><li>fix，fixed，fixed，fixing</li><li>differ, differed, differed, differing</li><li>hang，hung，hung（悬挂）</li><li>life，-，-，复数：lives</li><li>live，lived，lived，living</li><li>fly，flew 或 flied，flown 或 flied（飞，飞离 v.）</li><li>raise，raised，raised，raising（举起）</li><li>rain，rained，rained，raining</li><li>rise，rose，risen（升起，升高）</li><li>thow，第三人称单数：throws；现在进行时：throwing；过去式：threw；过去分词：thrown</li><li>begin，began，begun（最后变成了 gun 枪）</li></ul><h3 id="可数-不可数名词" tabindex="-1">可数/不可数名词 <a class="header-anchor" href="#可数-不可数名词" aria-label="Permalink to &quot;可数/不可数名词&quot;">​</a></h3><p>much 用于修饰不可数名词，不如 money 不可数，但是 dollar(s) 是可数的。</p><p>many 用于修饰可数名词，比如 many dollars。</p><h3 id="前后缀" tabindex="-1">前后缀 <a class="header-anchor" href="#前后缀" aria-label="Permalink to &quot;前后缀&quot;">​</a></h3><h4 id="inter-前缀" tabindex="-1">inter- 前缀 <a class="header-anchor" href="#inter-前缀" aria-label="Permalink to &quot;inter- 前缀&quot;">​</a></h4><p>inter 前缀在英语中表示</p><ul><li>“之间的”、（international 国际的）</li><li>“互相的”、（interaction 交流、互动）</li><li>在…… 之间，在…… 内部（internal）</li></ul><p>等含义。它常用于描述两个或多个事物之间的关系。</p><p>比如 interaction 表示交流、互动。</p><p>比如 internal 表示内部的。</p><h4 id="able-后缀" tabindex="-1">-able 后缀 <a class="header-anchor" href="#able-后缀" aria-label="Permalink to &quot;-able 后缀&quot;">​</a></h4><p>“- able”是一个常见的形容词后缀，它主要表示“能够…… 的；可以…… 的；值得…… 的”等意思。</p><h4 id="com-前缀" tabindex="-1">com- 前缀 <a class="header-anchor" href="#com-前缀" aria-label="Permalink to &quot;com- 前缀&quot;">​</a></h4><ol><li>表示“共同；一起”</li></ol><p>示例及解释：</p><ul><li>“combine”：由“com -（一起）+ bine（两个）”构成，意思是“结合；联合；混合”。例如：“We should combine theory with practice.（我们应该把理论和实践结合起来。）”</li><li>“compete”：来自“com -（共同）+ pete（追求）”，有“竞争；比赛”的意思。因为大家共同追求某个目标，所以会产生竞争。例如：“Several companies are competing for the contract.（几家公司正在为这份合同而竞争。）”</li><li>“cooperate”：“co -（也是‘共同’的意思，是 com - 的一种变体）+ operate（操作；工作）”，含义是“合作；协作”。比如：“The two countries are cooperating on a scientific research project.（这两个国家正在一个科研项目上合作。）”</li></ul><ol start="2"><li>表示“加强语气”</li></ol><p>示例及解释：</p><ul><li>“comfort”：“com -（加强语气）+ fort（力量）”，本义是“使更有力量；使振作”，后来演变为“安慰；慰藉”。例如：“Her kind words comforted him.（她亲切的话语安慰了他。）”</li><li>“commit”：由“com -（加强）+ mit（送；放）”组成，有“把…… 交托给；使承担义务；犯（错误、罪行等）”的意思。例如：“He committed himself to helping the poor.（他承诺帮助穷人。）”或者“He committed a crime.（他犯了罪。）”</li></ul><ol start="3"><li>表示“完全；全部”（在某些词中有此含义）</li></ol><p>示例及解释：</p><ul><li>“comprehensive”：“com -（完全）+ prehens（抓住）+ - ive（形容词后缀）”，意思是“全面的；综合的；广泛的”。例如：“The book gives a comprehensive account of American history.（这本书全面地叙述了美国历史。）”</li></ul>`,59)]))}const u=e(s,[["render",t]]);export{g as __pageData,u as default};
